def sieve_of_eratosthenes(limit):
    """
    Sieve of Eratosthenes algoritması kullanarak belirli bir sayıya kadar olan asal sayıları bulur.
    """
    is_prime = [True] * (limit + 1)
    if limit >= 0:
        is_prime[0] = False
    if limit >= 1:
        is_prime[1] = False

    for p in range(2, int(limit**0.5) + 1):
        if is_prime[p]:
            for multiple in range(p * p, limit + 1, p):
                is_prime[multiple] = False

    primes = [i for i, prime_status in enumerate(is_prime) if prime_status]
    return primes

if __name__ == "__main__":
    limit_number = 100  # Örnek olarak 100'e kadar olan asal sayıları bulalım
    prime_numbers = sieve_of_eratosthenes(limit_number)
    print(prime_numbers)

    limit_number_2 = 30
    prime_numbers_2 = sieve_of_eratosthenes(limit_number_2)
    print(prime_numbers_2)
